WITH filtered_ttns AS (
    -- Получаем список нужных ttns_id по pvid
    SELECT DISTINCT tss.ttns_id
    FROM pri_voz_spec_sgtin pvs
    INNER JOIN ttn_spec_sgtin tss 
        ON tss.sgtin = pvs.sgtin
    WHERE ttn_id IN ('256929','256171','256257','242013','240133','255732','253127','255441','260090','211505','260209','214898','162746','242044','258790','255849','255121','246599','246205','237567','255952','256020','218919','253125','203856','255723','256224','260203','210045','162594','181850','203901','224115','253628','248067','165640','257760','200377','259588','246771','242048','174717','260115','259979','211546','255753','236805','259748','225859','219126','228421','237565','248070','247473','248834','179703','259455','248488','223979','216668','256689','203857','248823','246765','248041','259834','241759','246122','256030','228423','246772','255443','234784','162729','255770','256401','189641','253439','246778','242072','242249','236477','241763','223475','202196','164214','256885','242050','222810','242052','209394','203876','242012','212387','246767','223022','246636','223484','218937','174729','246773','253959','213779','244831','256222','162743','164223','213772','222827','212422','253632','241723','246769','196150','204863','179705','213775','255944','252502','223478','202197','222813','212396','246770','256714','238370','177121','222791','253119','242049','248068','213793','253524','211544','224120','242444','213767','203880','247990','228420','259655','256283','255616','259038','205145','250944','225126','202198','258817','245699','209936','252121','178209','223264','177971','260091','251143','216463','228424','258611','250121','260023','256943','165638','212389','223265','245342','243541','253881','253797','202195','259972','203926','221442','179856','248957','222828','227679','241700','249987','223267','245904','225395','210021','252439','191112','203878','195154','247443','252218','256754','256926','179709','250275','242069','250091','183057','188977','256721','216678','165653','251323','259606','253208','227157','256128','190933','241776','253641','242426','240674','223166','243882','216679','162980','259458','241888','238458','246899','229397','167878','259741','246764','195435','183873','243883','212391','214957','199931','221009','227041','217938','223266','258119','210095','246591','223791','213768','219872','242077','201762','211849','216667','214525','257797','201307','254065','229342','191900','239096','230471','228426','217664','210479','253255','248005','203954','208565','256522','188843','211503','223268','249944','254318','215765','220591','246775','242062','182046','162593','171649','249563','243250','223614','206734','212584','204018','198548','238467','239741','250308','217293','205143','249164','246763','228459','247472','237371','187684','179355','215640','259873','179710','192584','154815','249847','244003','242273','198478','204798','249648','260295','201264','253766','203675','205190','236205','207670','192574','259538','209743','229387','209740','163818','245976','215887','245518','227523','196363','197228','214962','217505','162754','191974','219026','260150','209891','200558','219735','222488','219724','204722','219738','160404','178920','163196','199682','231723','227632','189761','227311','241445','221679','155940','181392','193318','214738','189266','214725','236963','231271','220052','242609','186164','207858','189755','167514','232394','206880','198283','155642','240721','212321','227721','200446','239672','222453','200451','166326','210375','197018','189642','232930','196917','186597','229201','227263','205442','195517','213795','184923','188920')
      AND pvs.tsd = 1
),
base AS (
    SELECT 
        tss.sgtin,                 -- теперь берем sgtin из ttn_spec_sgtin
        tss.ttns_id,
        ttn.receiverMarkAddressId,
        s.markaddressid,
        p.ocena_nds,
        ROW_NUMBER() OVER (PARTITION BY tss.ttns_id ORDER BY tss.sgtin) AS rn_inside,
        DENSE_RANK() OVER (ORDER BY tss.ttns_id) AS grp_num
    FROM ttn_spec_sgtin tss
    INNER JOIN filtered_ttns ft 
        ON ft.ttns_id = tss.ttns_id
    LEFT JOIN ttn 
        ON ttn.id = tss.ttn_id
    LEFT JOIN s_sklads s 
        ON s.id = ttn.sklad_id
    LEFT JOIN ttn_spec p 
        ON p.id = tss.ttns_id
)
SELECT 
    sgtin,
    ttns_id,
    receiverMarkAddressId,
    markaddressid,
    ocena_nds
FROM base where rn_inside = 1
ORDER BY 
    rn_inside,     -- сначала по одному из каждого ttns_id
    grp_num,       -- порядок групп
    sgtin;